            "oss.school": "\u062A\u0637\u0628\u064A\u0642 \u0628\u062F\u0627\u064A\u0629 \u0644\u0641\u0647\u0645 \u0623\u0646\u0645\u0627\u0637 SwiftUI \u0648Combine.",
