            "projects.domain.social": "\u05D7\u05D1\u05E8\u05EA\u05D9",
            "projects.domain.health": "\u05D8\u05DB\u05E0\u05D5\u05DC\u05D5\u05D2\u05D9\u05D4 \u05E8\u05E4\u05D5\u05D0\u05D9\u05EA",
